import { useRouter} from "next/router";
import Layout from "../components/Layout";

const Content = () => {
    const router = useRouter();
    return (
        <>
            <h1>{router.query.title}</h1>
            <p>Yeaa ini Post konten bruh!!</p>
        </>
    )
}

const Page = () =>  (
        <Layout>
           <Content/>
        </Layout>
)

export default Page;
